// Buffered reports the number of committed-but-unflushed rows.
func (inst *DeviceStore) Buffered() int { return inst.buffered }

// Flush drains the buffered rows to ClickHouse (Arrow IPC, ADR-0089
// pivot). Rows are durable when Flush returns, engine permitting. On
// insert failure the transferred records are retained and the next
// Flush ships them — Flush is retryable; DiscardPending drops them
// instead. An open (uncommitted) entity frame makes Flush error.
func (inst *DeviceStore) Flush(ctx context.Context) (n int, err error) {
	if inst.buffered == 0 && len(inst.pending) == 0 {
		return
	}
	// Ordered flush (ADR-0112 SD5): make the dimension facts this batch
	// references durable before the payload insert, so a referencing row is
	// never durable ahead of its descriptor. On failure nothing is
	// transferred yet — the buffered rows stay and the next Flush retries.
	if !inst.cfg.BestEffortStampFlush {
		for _, s := range inst.stampers {
			if _, ferr := s.Flush(ctx); ferr != nil {
				err = eh.Errorf("ordered flush of stampers: %w", ferr)
				return
			}
		}
	}
	records, err := lowlevel.InEntityDeviceTableTransferRecords(inst.dml, nil)
	if err != nil {
		err = eh.Errorf("transfer records: %w", err)
		return
	}
	records = append(inst.pending, records...)
	inst.pending = nil
	if len(records) > 0 {
		err = inst.exec.InsertArrow(ctx, DeviceTableName, records)
		if err != nil {
			inst.pending = records
			err = eh.Errorf("insert into %s: %w", DeviceTableName, err)
			return
		}
	}
	for _, rec := range records {
		rec.Release()
	}
	n = inst.buffered
	inst.buffered = 0
	for k := range inst.dirty {
		inst.notifyFlush(k) // durable now — release the views' dirty-window pins
	}
	clear(inst.dirty) // flushed — ClickHouse now serves the written state
	return
}

// DiscardPending drops every committed-but-unflushed row: records
// retained by a failed Flush, rows still in the DML builder, and an
// open (uncommitted) entity frame. It gives a failed Flush "never
// happened" semantics — ClickHouse state is the truth afterwards.
// Ambient stamps are cleared with the frame they were pushed for —
// including any pushed through Raw() — so an abandoned builder cannot
// leak its stamps onto later entities.
func (inst *DeviceStore) DiscardPending() {
	_ = lowlevel.InEntityDeviceTableRollbackEntity(inst.dml) // no-op error when no frame is open
	inst.dml.ClearMembershipsHighCardRef()                   // an abandoned Begin's stamps must not outlive its frame
	if records, err := lowlevel.InEntityDeviceTableTransferRecords(inst.dml, nil); err == nil {
		for _, rec := range records {
			rec.Release()
		}
	}
	for _, rec := range inst.pending {
		rec.Release()
	}
	inst.pending = nil
	inst.buffered = 0
	for k := range inst.dirty {
		inst.notifyWrite(k, nil) // the cached write never became durable — invalidate
	}
	clear(inst.dirty) // nothing local remains — ClickHouse is the truth
}

// Close discards everything unflushed and releases the store's Arrow
// builder; the store must not be used afterwards. Required for a
// clean shutdown under tracking/checked allocators — the default Go
// allocator needs no Close.
func (inst *DeviceStore) Close() {
	inst.DiscardPending()
	lowlevel.InEntityDeviceTableReleaseBuilder(inst.dml)
}

// DeviceCacheConfig parameterizes an attached read-through cache view.
type DeviceCacheConfig struct {
	// Capacity is the L1 capacity in entries, not bytes — budget
	// memory as Capacity × the largest expected entity payload. Zero
	// or negative selects the default (1024).
	Capacity int
	// FetchCriteria are the cache's batch-flush thresholds.
	FetchCriteria caching.FetchCriteria
	// FreshnessTTL enables age-based staleness onset (ADR-0100's
	// external-writer staleness story): entries older than this read
	// as stale — strict reads miss and queue a refetch, accept-stale
	// reads keep serving. Zero disables (staleness stays signal-only).
	FreshnessTTL time.Duration
	// NegativeTTL enables absent-key marking: keys a clean fetch did
	// not return are treated as absent for this long — misses on them
	// neither queue nor suspend work items, so replay loops over keys
	// that do not exist terminate. Zero disables.
	NegativeTTL time.Duration
}

// DeviceCache is the batched read-through, write-through KV view over a
// DeviceStore (ADR-0100 SD5): misses queue under work items and flush
// as one IN (…) lookup, and local writes populate the view at Commit —
// pinned until the store's Flush makes them durable — so reads after
// writes hit immediately. Admission is version-gated on the entity's
// Order timestamp: a raced refetch of an older row bounces off. Only
// EXTERNAL writers can leave the view stale; they need a caller-
// provided signal: MarkStale / Invalidate / InvalidateAll (a freshness
// TTL option exists on the underlying cache). Raw() commits and
// discarded writes invalidate instead of populating. Like the store
// it wraps, a view is single-goroutine. W is the work-item type (use
// struct{} when the suspend/replay machinery is not needed).
type DeviceCache[W comparable] struct {
	st    *DeviceStore
	cfg   DeviceCacheConfig
	cache *caching.ReadThroughCache[uint64, *DeviceEntity, W]
}

// NewDeviceCache attaches a read-through, write-through cache view to st,
// registering its write-through and flush hooks with the store. Views
// attach for the store's lifetime — there is no detach.
func NewDeviceCache[W comparable](st *DeviceStore, cfg DeviceCacheConfig) (inst *DeviceCache[W]) {
	if cfg.Capacity <= 0 {
		cfg.Capacity = 1024
	}
	inst = &DeviceCache[W]{st: st, cfg: cfg}
	inst.rebuild()
	// The hooks close over the view, not the cache instance, keeping
	// them correct if the cache is ever swapped out.
	st.onWrite = append(st.onWrite, func(k uint64, ent *DeviceEntity) {
		if ent == nil {
			inst.cache.Delete(k) // not materializable or discarded: invalidate
			return
		}
		inst.cache.AddItem(k, ent) // version-gated write-through
		inst.cache.Pin(k)          // dirty-window latch, released by Flush
	})
	st.onFlush = append(st.onFlush, func(k uint64) { inst.cache.Unpin(k) })
	return
}

func (inst *DeviceCache[W]) rebuild() {
	opts := []caching.CacheOption[uint64, *DeviceEntity, W]{
		// Admission mirrors the table's newest-row-per-key semantics:
		// the Order timestamp is the entity's monotonic version.
		caching.WithVersioning[uint64, *DeviceEntity, W](func(e *DeviceEntity) int64 { return e.Ts.UnixNano() }),
	}
	if inst.cfg.FreshnessTTL > 0 {
		opts = append(opts, caching.WithFreshnessTTL[uint64, *DeviceEntity, W](inst.cfg.FreshnessTTL))
	}
	if inst.cfg.NegativeTTL > 0 {
		opts = append(opts, caching.WithNegativeCaching[uint64, *DeviceEntity, W](inst.cfg.NegativeTTL))
	}
	inst.cache = caching.NewReadThroughCache[uint64, *DeviceEntity, W](inst.cfg.Capacity, &deviceFetcher{st: inst.st}, inst.cfg.FetchCriteria, opts...)
}

// Get retrieves an entity by Key through the cache; local writes are
// visible immediately (write-through). A miss queues the key for the
// next batch fetch (the caching suspend/replay contract). A miss can
// also mean the batched fetch errored (misses swallow fetch errors;
// the circuit breaker backs off) — GetFetch surfaces the error
// instead, and the store's Latest stays the authoritative check. The
// returned entity is shared with the cache: treat it as immutable.
func (inst *DeviceCache[W]) Get(key uint64) (ent *DeviceEntity, found bool) {
	return inst.cache.Get(key)
}

// GetFetch is the single-lookup read: the cached entity when present,
// otherwise one immediate batched point fetch — fetch errors surface
// instead of reading as misses, so found=false with err=nil is the
// authoritative absent. The fetched row is cached unless the key is
// in the dirty write window. Prefer Get plus the work-item protocol
// when batching lookups across a frame; the initial miss here also
// queues the key, so a later batch fetch may include it redundantly
// (harmless).
func (inst *DeviceCache[W]) GetFetch(ctx context.Context, key uint64) (ent *DeviceEntity, found bool, err error) {
	ent, found = inst.cache.Get(key)
	if found {
		return
	}
	ents, err := inst.st.queryEntities(ctx, inst.st.fetchLatestSQL([]uint64{key}))
	if err != nil {
		err = eh.Errorf("get-fetch: %w", err)
		return
	}
	for _, e := range ents {
		if e.ID != key {
			continue
		}
		ent = e
		found = true
		if _, d := inst.st.dirty[key]; !d {
			inst.cache.AddItem(key, e)
		}
	}
	return
}

// WorkItem marks the current work item for the cache's miss bookkeeping.
func (inst *DeviceCache[W]) WorkItem(w W) iter.Seq[functional.NilIteratorValueType] {
	return inst.cache.WorkItem(w)
}

// IterateReadyWorkItems flushes the queued keys when the fetch criteria
// are met and replays the work items that had misses.
func (inst *DeviceCache[W]) IterateReadyWorkItems(ctx context.Context) iter.Seq[W] {
	return inst.cache.IterateReadyWorkItems(ctx)
}

// IterateRestWorkItems forces a fetch of all queued keys and replays
// the pending work items.
func (inst *DeviceCache[W]) IterateRestWorkItems(ctx context.Context) iter.Seq[W] {
	return inst.cache.IterateRestWorkItems(ctx)
}

// AdvanceEpoch advances the cache's pinning epoch — call once per
// frame / batch so untouched L1 entries become evictable.
func (inst *DeviceCache[W]) AdvanceEpoch() {
	inst.cache.AdvanceEpoch()
}

// MarkStale flags the key's cached entry as stale — the external-writer
// signal: the next strict read misses and queues a refetch, while
// accept-stale reads keep serving the old value until it lands.
func (inst *DeviceCache[W]) MarkStale(key uint64) {
	inst.cache.MarkAsStale(key)
}

// MarkStaleIfOlder is the version-carrying external-writer signal:
// it stales the cached entry only if its Order is below order, so a
// redundant signal for a version the view already holds is free —
// the natural sink for an invalidation stream carrying (key, Order).
func (inst *DeviceCache[W]) MarkStaleIfOlder(key uint64, order time.Time) {
	inst.cache.MarkAsStaleIfOlder(key, order.UnixNano())
}

// Invalidate drops the key's cached entry (L1 and stash).
func (inst *DeviceCache[W]) Invalidate(key uint64) {
	inst.cache.Delete(key)
}

// InvalidateAll drops every cached entry — the bulk external-writer
// signal (e.g. after an import). In-flight miss bookkeeping (queued
// keys, pending work items) and the dirty-window pins are dropped
// with it: call between frames, with no suspended work and no
// unflushed local writes (the fetcher's dirty-guard keeps pre-write
// rows out of the cleared cache until the next Flush, at the cost of
// misses on those keys).
func (inst *DeviceCache[W]) InvalidateAll() {
	inst.cache.Clear()
}

// GetLive is the cached state-view read: the cache's newest row for
// the key with the tombstone read as absent — exact under this
// process's single writer (local writes invalidate); external writers
// need MarkStale / Invalidate. The store's uncached GetLive stays
// the authoritative read. A miss queues the batch fetch like Get.
func (inst *DeviceCache[W]) GetLive(key uint64) (ent *DeviceEntity, found bool) {
	ent, found = inst.cache.Get(key)
	if found && ent.IsTombstone() {
		ent = nil
		found = false
	}
	return
}

// GetLiveAcceptStale is the stale-while-revalidate state-view read:
// a stale entry is served immediately (stale=true) while the refetch
// queues in the background — pair with the work-item replay loop.
// Tombstones read as absent; stale then reports whether that verdict
// came from a stale entry.
func (inst *DeviceCache[W]) GetLiveAcceptStale(key uint64) (ent *DeviceEntity, found bool, stale bool) {
	ent, found, stale = inst.cache.GetAcceptStale(key)
	if found && ent.IsTombstone() {
		ent = nil
		found = false
	}
	return
}

// fetchLatestSQL is the batched newest-row-per-key point lookup shared
// by the cache fetcher and GetFetch.
func (inst *DeviceStore) fetchLatestSQL(keys []uint64) string {
	var sb strings.Builder
	sb.WriteString("SELECT * FROM ")
	sb.WriteString(DeviceTableName)
	sb.WriteString(" WHERE " + DeviceColKey + " IN (")
	for i, k := range keys {
		if i > 0 {
			sb.WriteByte(',')
		}
		sb.WriteString(deviceKeyLiteral(k))
	}
	sb.WriteString(") ORDER BY " + DeviceColOrder + " DESC LIMIT 1 BY " + DeviceColKey)
	sb.WriteString(deviceArrowOutputSettings)
	return sb.String()
}

// deviceFetcher implements caching.ItemFetcherI for attached cache views —
// an unexported shim so the fetch plumbing stays off the store's
// public method set.
type deviceFetcher struct{ st *DeviceStore }

var _ caching.ItemFetcherI[uint64, *DeviceEntity] = (*deviceFetcher)(nil)

// DeterminePartition implements caching.ItemFetcherI. Single partition
// in v1 (one table, one server).
func (inst *deviceFetcher) DeterminePartition(key uint64) uint64 { return 0 }

// FetchItemSinglePartition implements caching.ItemFetcherI: one batched
// point lookup per fetch. Duplicate versions collapse newest-first.
// Dirty keys (written locally, not yet flushed) are fetched but not
// cached. With write-through the version gate already rejects the
// pre-write row while the newer entry is resident; this guard is the
// remaining defense for dirty keys the views could NOT materialize
// (Raw commits, discarded writes) and for InvalidateAll inside a
// dirty window, where the cache is cold and the gate has nothing to
// compare against.
func (inst *deviceFetcher) FetchItemSinglePartition(ctx context.Context, partition uint64, keys []uint64, target caching.ItemTargetI[uint64, *DeviceEntity]) (err error) {
	ents, err := inst.st.queryEntities(ctx, inst.st.fetchLatestSQL(keys))
	if err != nil {
		return
	}
	for _, ent := range ents {
		if _, d := inst.st.dirty[ent.ID]; d {
			continue
		}
		target.AddItem(ent.ID, ent)
	}
	return
}

// Baked ADR-0066 Filter artefacts: rows carrying a conforming
// component. Generated from Plan ⋈ IR; membership ids are literals.
const (
	deviceScanIdentityFilter = "has(\"tv:symbol:lr:lr:u64:2q:0:0:0::data\", 1) AND countEqual(\"tv:symbol:lr:lr:u64:2q:0:0:0::data\", 1) = 1 AND countEqual(\"tv:symbol:lr:lr:u64:2q:0:0:0::data\", 2) <= 1"
	deviceScanBatteryFilter  = "has(\"tv:u64Array:lr:lr:u64:2q:0:0:0::data\", 1) AND countEqual(\"tv:u64Array:lr:lr:u64:2q:0:0:0::data\", 1) = 1"
	deviceScanTaggedFilter   = "has(\"tv:symbolArray:lr:lr:u64:2q:0:0:0::data\", 1) AND countEqual(\"tv:symbolArray:lr:lr:u64:2q:0:0:0::data\", 1) = 1"
	deviceScanLocatedFilter  = "has(\"tv:geoPoint:lr:lr:u64:2q:0:0:0::data\", 1) AND countEqual(\"tv:geoPoint:lr:lr:u64:2q:0:0:0::data\", 1) = 1"
)

// ScanIdentity iterates the entities whose rows carry a conforming Identity
// component, ordered by (Order, Key) — deterministic across ties.
// opts.ExtraPredicate (trusted raw SQL over the physical columns —
// never untrusted input) further restricts the scan; opts.Limit
// caps the row count. The Filter artefact uses ClickHouse
// built-ins only, so this is a single SELECT — no helper UDFs, no
// multi-statement script (the ExecutorI contract). The sequence is
// single-use; ctx must stay valid until iteration completes; an
// error ends it as a final (nil, err) pair. Scans see only flushed
// rows.
func (inst *DeviceStore) ScanIdentity(ctx context.Context, opts recordstore.ScanOpts) iter.Seq2[*DeviceEntity, error] {
	where := deviceScanIdentityFilter
	if opts.ExtraPredicate != "" {
		where = "(" + where + ") AND (" + opts.ExtraPredicate + ")"
	}
	sql := "SELECT * FROM " + DeviceTableName +
		" WHERE " + where +
		" ORDER BY " + DeviceColOrder + " ASC, " + DeviceColKey + " ASC"
	if opts.Limit > 0 {
		sql += " LIMIT " + strconv.Itoa(opts.Limit)
	}
	sql += deviceArrowOutputSettings
	return inst.iterateEntities(ctx, sql)
}

