// Latest returns the newest row for key, tombstone-blind (the raw
// row-level primitive — a deleted key still returns its tombstone
// row; GetLive is the interpreted state-view read). Reads see only
// flushed rows.
func (inst *DeviceStore) Latest(ctx context.Context, key uint64) (ent *DeviceEntity, found bool, err error) {
	sql := "SELECT * FROM " + DeviceTableName +
		" WHERE " + DeviceColKey + " = " + deviceKeyLiteral(key) +
		" ORDER BY " + DeviceColOrder + " DESC LIMIT 1" + deviceArrowOutputSettings
	ents, err := inst.queryEntities(ctx, sql)
	if err != nil || len(ents) == 0 {
		return
	}
	ent = ents[0]
	found = true
	return
}

// Replay iterates the rows for key with the order column >= fromOrder
// in ascending order — the event-replay primitive. A zero fromOrder
// replays everything (zero time.Time has no defined UnixNano;
// recordstore.SeqTs(0) is the equivalent explicit bound);
// opts.To bounds the replay exclusively ("state as of To") and
// opts.Limit caps the row count. The sequence is single-use; ctx
// must stay valid until iteration completes; the query may execute
// at call time or lazily during iteration (buffered in v1 — a
// streaming executor changes nothing visible); an error ends the
// sequence as a final (nil, err) pair. Reads see only flushed rows.
func (inst *DeviceStore) Replay(ctx context.Context, key uint64, fromOrder time.Time, opts recordstore.ReplayOpts) iter.Seq2[*DeviceEntity, error] {
	sql := "SELECT * FROM " + DeviceTableName +
		" WHERE " + DeviceColKey + " = " + deviceKeyLiteral(key)
	if !fromOrder.IsZero() {
		sql += " AND " + DeviceColOrder + " >= fromUnixTimestamp64Nano(" + strconv.FormatInt(fromOrder.UnixNano(), 10) + ")"
	}
	if !opts.To.IsZero() {
		sql += " AND " + DeviceColOrder + " < fromUnixTimestamp64Nano(" + strconv.FormatInt(opts.To.UnixNano(), 10) + ")"
	}
	sql += " ORDER BY " + DeviceColOrder + " ASC"
	if opts.Limit > 0 {
		sql += " LIMIT " + strconv.Itoa(opts.Limit)
	}
	sql += deviceArrowOutputSettings
	return inst.iterateEntities(ctx, sql)
}

// --- state view (Delete / GetLive; ADR-0100 SD4). Versioned writes
// go through Begin — appending a new version IS the update. ---

// Delete appends a tombstone row for id (no components; lifecycle marks
// the deletion). The tombstone writes through to attached cache views
// like any commit — a versioned deletion, so GetLive reads the key as
// absent immediately.
func (inst *DeviceStore) Delete(id uint64, ts time.Time) (err error) {
	lowlevel.InEntityDeviceTableBeginEntity(inst.dml)
	lowlevel.InEntityDeviceTableSetId(inst.dml, id)
	lowlevel.InEntityDeviceTableSetTimestamp(inst.dml, ts)
	lowlevel.InEntityDeviceTableSetLifecycle(inst.dml, recordstore.LifecycleTombstone)
	err = lowlevel.InEntityDeviceTableCommitEntity(inst.dml)
	if err != nil {
		_ = lowlevel.InEntityDeviceTableRollbackEntity(inst.dml) // discard the failed frame; the store stays usable
		return
	}
	inst.buffered++
	inst.dirty[id] = struct{}{}
	inst.notifyWrite(id, &DeviceEntity{ID: id, Ts: ts, Lifecycle: recordstore.LifecycleTombstone})
	return
}

// GetLive is Latest plus tombstone interpretation: newest row wins, a
// tombstone reads as absent — the state-view read (the cache view
// carries the cached twin).
func (inst *DeviceStore) GetLive(ctx context.Context, key uint64) (ent *DeviceEntity, found bool, err error) {
	ent, found, err = inst.Latest(ctx, key)
	if err != nil || !found {
		return
	}
	if ent.IsTombstone() {
		ent = nil
		found = false
	}
	return
}

// --- decode (Arrow → entity bags). ---

// deviceSectionReaderI is the uniform slice of the generated read-access
// readers. Column indices stay at their constructor defaults — the
// schema order a SELECT * returns.
type deviceSectionReaderI interface {
	LoadFromRecord(raruntime.RecordI) error
	Release()
}

func (inst *DeviceStore) queryEntities(ctx context.Context, sql string) (ents []*DeviceEntity, err error) {
	for rec, rerr := range inst.exec.QueryArrow(ctx, sql) {
		if rerr != nil {
			err = eh.Errorf("query entities: %w", rerr)
			return
		}
		batch, derr := decodeDeviceRecord(rec)
		rec.Release()
		if derr != nil {
			err = derr
			return
		}
		ents = append(ents, batch...)
	}
	return
}

// iterateEntities adapts the buffered query path to the single-use
// iterator contract shared by Replay and the Scan verbs: entities
// yield in query order; an error yields once as (nil, err) and ends
// the sequence.
func (inst *DeviceStore) iterateEntities(ctx context.Context, sql string) iter.Seq2[*DeviceEntity, error] {
	return func(yield func(*DeviceEntity, error) bool) {
		ents, err := inst.queryEntities(ctx, sql)
		if err != nil {
			yield(nil, err)
			return
		}
		for _, ent := range ents {
			if !yield(ent, nil) {
				return
			}
		}
	}
}

// decodeDeviceRecord reads one fetched Arrow record into entity bags:
// envelope from the plain readers, components via presence-gated,
// membership-matched reads (fat rows carry optional components — the
// kind-homogeneous helpers cannot decode them).
func decodeDeviceRecord(rec arrow.RecordBatch) (ents []*DeviceEntity, err error) {
	idR := lowlevel.NewReadAccessDeviceTablePlainEntityIdAttributes()
	tsR := lowlevel.NewReadAccessDeviceTablePlainEntityTimestampAttributes()
	lcR := lowlevel.NewReadAccessDeviceTablePlainEntityLifecycleAttributes()
	symbolR := lowlevel.NewReadAccessDeviceTableTaggedSymbol()
	u64ArrayR := lowlevel.NewReadAccessDeviceTableTaggedU64Array()
	symbolArrayR := lowlevel.NewReadAccessDeviceTableTaggedSymbolArray()
	geoPointR := lowlevel.NewReadAccessDeviceTableTaggedGeoPoint()
	readers := []deviceSectionReaderI{idR, tsR, lcR, symbolR, u64ArrayR, symbolArrayR, geoPointR}
	for _, r := range readers {
		err = r.LoadFromRecord(rec)
		if err != nil {
			err = eh.Errorf("load device reader from record: %w", err)
			return
		}
	}
	defer func() {
		for _, r := range readers {
			r.Release()
		}
	}()

	n := idR.ValueId.Len()
	tsType, ok := tsR.ValueTs.DataType().(*arrow.TimestampType)
	if !ok {
		err = eh.Errorf("order column is not a timestamp (got %s)", tsR.ValueTs.DataType())
		return
	}
	ents = make([]*DeviceEntity, 0, n)
	for i := range n {
		ent := &DeviceEntity{
			ID:        idR.ValueId.Value(i),
			Ts:        tsR.ValueTs.Value(i).ToTime(tsType.Unit).UTC(),
			Lifecycle: lcR.ValueLifecycle.Value(i),
		}
		{
			row, ok, e := identityReadRow(i, symbolR.GetAttributes(), symbolR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read identity component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Identity = option.Some(row)
			}
		}
		{
			row, ok, e := batteryReadRow(i, u64ArrayR.GetAttributes(), u64ArrayR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read battery component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Battery = option.Some(row)
			}
		}
		{
			row, ok, e := taggedReadRow(i, symbolArrayR.GetAttributes(), symbolArrayR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read tagged component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Tagged = option.Some(row)
			}
		}
		{
			row, ok, e := locatedReadRow(i, geoPointR.GetAttributes(), geoPointR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read located component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Located = option.Some(row)
			}
		}
		ents = append(ents, ent)
	}
	return
}
